};

export const TemplateCard = ({
  badge,
  onToggleFavorite,
  onUseTemplate,
  onViewDetails,
  template,
}: TemplateCardProps) => {
  const { t } = useTranslation('actionPagesBuilder');
  const backgroundColor = useColorModeValue('neutral.0', 'neutral.750');
  const primaryForegroundColor = useColorModeValue('neutral.700', 'neutral.0');
  const secondaryForegroundColor = useColorModeValue('neutral.600', 'neutral.400');
  const starForegroundColor = useColorModeValue('neutral.400', 'neutral.600');
  const activeStarForegroundColor = useColorModeValue('blue.400', 'blue.400');

  return (
    <MotionBox
      alignContent="center"
      alignItems="center"
      background={backgroundColor}
      borderRadius="2xl"
      display="flex"
      flexDirection="column"
      layout
      layoutId={`template-${template.id}`}
      padding={6}
      position="relative"
    >
      <StarIcon
        color={template.isFavorite ? activeStarForegroundColor : starForegroundColor}
        cursor="pointer"
        onClick={() => onToggleFavorite?.(template)}
        position="absolute"
        right={4}
        top={4}
      />
      <Flex flexDirection="column">
        <Flex flexDirection="row" justify="space-between" maxWidth="240px" overflow="hidden">
