          </Text>
          <Flex alignItems="center" minWidth="32px" overflow="hidden">
            {badge}
          </Flex>
        </Flex>
        <Text
          color={secondaryForegroundColor}
          overflow="hidden"
          textOverflow="ellipsis"
          textStyle="metaRegular"
          whiteSpace="nowrap"
          width="250px"
        >
          {template.pageType}
        </Text>
        <Flex marginBottom={4} marginTop={4}>
          <TemplatePlaceholderIcon height="177px" width="250px" />
        </Flex>
        <Flex flexDirection="row">
          <Button
            height={8}
            marginRight={4}
            onClick={() => onViewDetails?.(template)}
            variant="secondary"
            width="117px"
          >
            {t('viewDetails')}
          </Button>
          <Button
            height={8}
            onClick={() => onUseTemplate?.(template)}
            variant="primary"
            width="117px"
          >
            {t('useTemplate')}
          </Button>
        </Flex>
      </Flex>
    </MotionBox>
  );
};

