  const variants: Variants = useMemo(
    () => ({
      selected: {
        height: 4,
        maxHeight: 4,
        maxWidth: 32,
        minHeight: 4,
        minWidth: 32,
        width: 32,
      },
      unselected: {
        height: 4,
        maxHeight: 4,
        maxWidth: 16,
        minHeight: 4,
        minWidth: 16,
        width: 16,
      },
    }),
    []
  );

  return (
    <MotionBox
      __css={{ transition: 'background .2s ease' }}
      animate={selected ? 'selected' : 'unselected'}
      background={selected ? 'blue.600' : backgroundColor}
      borderRadius="20px"
      initial="false"
      marginLeft="2px"
      marginRight="2px"
      transformOrigin={selected ? '16px 2px' : '8px 2px'}
      variants={variants}
    />
  );
