      whileHover={{ scale: disabled ? 1 : 1.1 }}
      whileTap={{ scale: disabled ? 1 : 0.9 }}
      width="32px"
    >
      {Children.map(children, (child, idx) =>
        cloneElement(child, {
          color: foregroundColor,
          height: '16px',
          key: idx.toString(),
          width: '16px',
        })
      )}
    </MotionBox>
