export const Carousel = ({ children, variant = 'primary', ...props }: CarouselProps) => {
  const { t } = useTranslation('common');
  const panels = Children.toArray(children);
  const [[currentPage, direction], setCurrentPage] = useState([0, 0]);

  const setPage = (newPage: number) => {
    setCurrentPage(([prevPage]) => [newPage, newPage - prevPage]);
  };

  const previousPage = () => {
    setPage(Math.max(0, currentPage - 1));
  };

  const nextPage = () => {
    setPage(Math.min(panels.length - 1, currentPage + 1));
  };

  return (
    <MotionBox display="flex" flexDirection="column" height="full" layout width="full">
      <PanelSlider currentPage={currentPage} direction={direction} variant="horizontal" {...props}>
        {panels}
      </PanelSlider>
      <Flex flexDirection="row" justifyContent="space-between" marginTop="16px">
        <Flex alignContent="center" alignItems="center" flexDirection="row" justifyContent="center">
          <CarouselNavigationButton
            disabled={currentPage === 0}
            marginRight="8px"
            onClick={previousPage}
            title={t('button.previous')}
            variant={variant}
          >
            <ChevronLeftIcon />
          </CarouselNavigationButton>
          <CarouselNavigationButton
            disabled={currentPage === panels.length - 1}
            onClick={nextPage}
            title={t('button.next')}
            variant={variant}
          >
            <ChevronRightIcon />
          </CarouselNavigationButton>
        </Flex>
        <Flex alignContent="center" alignItems="center" flexDirection="row" justifyContent="center">
          {panels.map((_, idx) => (
            <CarouselIndicator key={idx} selected={currentPage === idx} />
          ))}
        </Flex>
      </Flex>
    </MotionBox>
  );
};

