import { Flex, StyleProps } from '@chakra-ui/react';
import { ActionPageFinancePreset } from '@domain/actionPages';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { Button } from '@ui/components/Button/Button';
import { MaskedInputControl } from '@ui/components/formControls/MaskedInputControl';
import { Label } from '@ui/components/typography';
import { formatCurrency } from '@ui/utils/formatCurrency';
import currency from 'currency.js';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { FeaturedAmountBadge } from './FeaturedAmountBadge';

type Props = StyleProps & {
  actionButtonBgColor?: string;
  actionButtonHoverBgColor?: string;
  actionButtonTextColor?: string;
  amountPresetsOther?: boolean;
  amounts?: ActionPageFinancePreset[];
  enableButtons?: boolean;
  maximumAmount?: number | null;
  minimumAmount?: number;
  otherAmount?: string;
  selectedAmount?: ActionPageFinancePreset | null;
  setOtherAmount: (val: string | undefined) => void;
  setSelectedAmount: (amount: ActionPageFinancePreset | null) => void;
  setShowOtherInput: (val: boolean) => void;
  showLoadingOnAmounts?: boolean;
  showOtherInput?: boolean;
};

type ThemeButtonProps = {
  amount: string | number | undefined;
  bgColor?: string;
  bgHoverColor?: string;
  selectedAmount?: string | number | undefined;
  showOtherInput?: boolean;
  textColor?: string;
};

const getThemeButtonColors = ({
  amount,
  bgColor,
  bgHoverColor,
  selectedAmount,
  showOtherInput,
  textColor,
}: ThemeButtonProps) => {
  if (bgColor && bgHoverColor && textColor) {
    const activeStyles = {
      backgroundColor: bgColor,
      borderColor: bgColor,
      borderWidth: '2px',
      color: textColor,
    };

    // Solid background if nothing is selected or this button has been selected
    if ((!selectedAmount && !showOtherInput) || selectedAmount === amount) {
      return {
        _active: activeStyles,
        _hover: {
          backgroundColor: bgHoverColor,
        },
        backgroundColor: bgColor,
        borderColor: bgColor,
        color: textColor,
      };
    }

    // If 1 button is selected, then every other button is just greyish
    return {
      _active: activeStyles,
      _hover: activeStyles,
      backgroundColor: 'neutral.100',
      borderColor: 'neutral.100',
      borderWidth: '2px',
      color: 'neutral.600',
    };
  }
  return {};
};

// Flexes the layout based upon how many amounts are given
// 1 - full width
// 2 - 50/50
// 3 - 33/33/33
// 4 - 25/25/25/25
// 5 - 33/33/33 and 50/50
// 6 - 33/33/33
// 7 - and up, is all going to be 25
// Exceptions are buttons with amount and description, which will always be 100% width
export const AmountPresetsContainer = ({
  actionButtonBgColor,
  actionButtonHoverBgColor,
  actionButtonTextColor,
  amountPresetsOther = false,
  amounts = [],
  enableButtons = true,
  maximumAmount,
  minimumAmount,
  otherAmount,
  selectedAmount,
  setOtherAmount,
  setSelectedAmount,
  setShowOtherInput,
  showLoadingOnAmounts,
  showOtherInput = false,
  ...styleProps
}: Props) => {
  const { t } = useTranslation('common');
  const total = useTotalAmount();

  const error = useMemo(() => {
    const amountInDollars = total / 100;

    if (!!maximumAmount && total > maximumAmount) {
      const maximumCurrencyValue = currency(maximumAmount / 100);

      return t('transactionLimits.error.maximum', {
        maximumAmount: formatCurrency(maximumCurrencyValue.intValue, {
          hideDecimal: maximumCurrencyValue.cents() === 0,
        }),
      });
    }

    if (!!minimumAmount && amountInDollars !== 0 && amountInDollars < minimumAmount) {
      const minimumCurrencyValue = currency(minimumAmount);

      return t('transactionLimits.error.minimum', {
        minimumAmount: formatCurrency(minimumCurrencyValue.intValue, {
          hideDecimal: minimumCurrencyValue.cents() === 0,
        }),
      });
    }

    return undefined;
  }, [maximumAmount, minimumAmount, t, total]);

  if ((amounts ?? []).length === 0 && !amountPresetsOther && !showOtherInput) {
    return null;
  }

  return (
    <Flex flexDirection="column" width="full" {...styleProps} marginTop={3}>
      <Flex flexWrap="wrap" gap={2} justifyContent="center">
        {amounts.map((amount) => (
          <Button
            flex={
              amount.description
                ? 1
                : amounts.length === 5 || amounts.length === 6
                  ? // Needs to be below 33%, less to account for margins to get 1/3
                    '0 0 30%'
                  : // Needs to be below 25%, less to account for margins to get 1/4
                    '0 0 20%'
            }
            flexGrow={1}
            height="64px"
            isActive={amount === selectedAmount}
            isDisabled={amount !== selectedAmount && showLoadingOnAmounts}
            isLoading={amount === selectedAmount && showLoadingOnAmounts}
            {...getThemeButtonColors({
              amount: amount.amount,
              bgColor: actionButtonBgColor,
              bgHoverColor: actionButtonHoverBgColor,
              selectedAmount: selectedAmount?.amount,
              showOtherInput,
              textColor: actionButtonTextColor,
            })}
            key={amount.id}
            minWidth={amount.description ? '100%' : '20%'}
            onClick={() => {
              if (!enableButtons) {
                return;
              }

              setShowOtherInput(false);
              setOtherAmount(undefined);
              setSelectedAmount(amount);
            }}
            variant="donationAmount"
          >
            {amount.description ? (
              <Flex alignItems="center" justifyContent="space-between" margin={1} width="full">
                {amount.amount}
                <Flex align="center" gap={2} justify="end">
                  <Label color="currentColor" ml={20} textAlign="right" whiteSpace="normal">
                    {amount.description}
