import { Box, Flex } from '@chakra-ui/react';
import { Fund, FundGroup } from '@domain/actionPageFunds';
import {
  ActionPageFinancePreset,
  ActionPageFundSelection,
  AmountAllocation,
} from '@domain/actionPages';
import { SourceFrequency } from '@domain/entry';
import { IProduct } from '@domain/product';
import { MultiSwitch } from '@ui/components/molecules/MultiSwitch';
import { Heading } from '@ui/components/typography';
import { getSelectedAmount } from '@ui/utils/getSelectedAmount';
import { parseDate } from '@ui/utils/parseDate';
import currency from 'currency.js';
import { isAfter } from 'date-fns';
import { useCallback, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { AmountPresetsContainer } from './AmountPresetsContainer';
import { FundsAndAmountsContainer } from './FundAndAmountsContainer';
import { FuturePledgeBanner } from './FuturePledgeBanner';
import { GoaaAlert } from './GoaaAlert';
import { useGiftOfAnyAmount } from './hooks/useGiftOfAnyAmount';
import { ProductRadioGroup } from './ProductRadioGroup';
import { RecurringUpgradeBanner } from './RecurringUpgradeBanner';

export const OrderOfSourceFrequencies = [
  SourceFrequency.Once,
  SourceFrequency.Daily,
  SourceFrequency.Weekly,
  SourceFrequency.BiWeekly,
  SourceFrequency.Monthly,
  SourceFrequency.BiMonthly,
  SourceFrequency.Quarterly,
  SourceFrequency.SemiAnually,
  SourceFrequency.Yearly,
];

export type DonationFundSelection = Fund & ActionPageFundSelection;

export type DonationSelectorProps = {
  actionButtonBgColor?: string;
  actionButtonHoverBgColor?: string;
  actionButtonTextColor?: string;
  addFund?: (fundId: string) => void;
  additionalFunds: DonationFundSelection[];
  allowModificationsOfFunds?: boolean;
  amountAllocations: AmountAllocation[];
  amountPresetsOther?: boolean;
  amounts?: ActionPageFinancePreset[];
  displayFrequencyAsCheckbox?: boolean;
  donationCaption?: React.ReactNode;
  frequencies: SourceFrequency[];
  fundGroups: FundGroup[];
  funds: DonationFundSelection[];
  futurePledgeDate?: string | null;
  futurePledgeMessage?: string;
  futurePledgeSelected?: boolean;
  goaaEnabled?: boolean;
  goaaForceSelection?: boolean;
  hideFrequencySwitch?: boolean;
  isOverwriteFunds?: boolean;
  minimumGiftAmount?: number;
  multiFundExpanded?: boolean;
  otherAmount?: string;
  primaryAccountId?: string;
  products?: IProduct[];
  productsForRecurringOnly?: boolean;
  recurringMessage?: string | null;
  removeFund?: (fundId: string, amountAllocations: AmountAllocation[]) => void;
  selectedAmount?: ActionPageFinancePreset | null;
  selectedFrequency: SourceFrequency;
  selectedProduct?: IProduct | null;
  setAllocationAmount?: (val: AmountAllocation[]) => void;
  setFuturePledgeSelected?: (val: boolean) => void;
  setOtherAmount: (val: string | undefined, balanceAmountAllocations?: boolean) => void;
  setSelectedAmount: (amount: ActionPageFinancePreset | null) => void;
  setSelectedFrequency: (frequency: SourceFrequency) => void;
  setSelectedProduct?: (gift: IProduct | null | undefined) => void;
  setShowOtherInput: (val: boolean) => void;
  showFundsAndAmounts?: boolean;
  showLoadingOnAmounts?: boolean;
  showOtherInput?: boolean;
  transactionLimit?: number | null;
  transactionMinimum?: number;
};

export const DonationSelector = ({
  actionButtonBgColor,
  actionButtonHoverBgColor,
  actionButtonTextColor,
  addFund,
  additionalFunds,
  allowModificationsOfFunds = true,
  amountAllocations,
  amountPresetsOther,
  amounts,
  displayFrequencyAsCheckbox,
  donationCaption,
  frequencies,
  fundGroups,
  funds,
  futurePledgeDate,
  futurePledgeMessage,
  futurePledgeSelected,
  goaaEnabled,
  goaaForceSelection,
  hideFrequencySwitch,
  isOverwriteFunds = false,
  minimumGiftAmount,
  multiFundExpanded,
  otherAmount,
  primaryAccountId,
  products,
  productsForRecurringOnly,
  recurringMessage,
  removeFund,
  selectedAmount,
  selectedFrequency,
  selectedProduct,
  setAllocationAmount,
  setFuturePledgeSelected,
  setOtherAmount,
  setSelectedAmount,
  setSelectedFrequency,
  setSelectedProduct,
  setShowOtherInput,
  showFundsAndAmounts = true,
  showLoadingOnAmounts,
  showOtherInput,
  transactionLimit,
  transactionMinimum,
}: DonationSelectorProps) => {
  const { t } = useTranslation(['actionPagesBuilder', 'common']);
  const selectedProductValue =
    selectedProduct?.id || (goaaForceSelection ? (products?.[0]?.id ?? '') : 'no-product');

  const options = useMemo(
    () =>
      frequencies
        .sort((a, b) => OrderOfSourceFrequencies.indexOf(a) - OrderOfSourceFrequencies.indexOf(b))
        .map((frequency) => ({
          label:
            frequency === SourceFrequency.Once
              ? t(`common:frequency.onetime`)
              : t(`common:frequency.${frequency}`),
          value: frequency,
        })),
    [frequencies, t]
  );

  const selectedOption = useMemo(() => {
    const opt = options.find((option) => option.value === selectedFrequency);

    if (!opt) {
      return -1;
    }

    return options.indexOf(opt);
  }, [options, selectedFrequency]);

  const amount = getSelectedAmount(selectedAmount, otherAmount);

  const { isGiftOfAnyAmountAlertDisplayed, isGiftOfAnyAmountAvailable } = useGiftOfAnyAmount({
    amount: amount ? currency(amount).intValue : undefined,
    goaaEnabled,
    minimumGiftAmount,
    productsForRecurringOnly,
    selectedFrequency,
  });

  const showFrequencySwitch =
    ((amountPresetsOther && showOtherInput) || (amounts ?? []).length > 0) &&
    !displayFrequencyAsCheckbox &&
    !(options.length === 1 && options[0].value === SourceFrequency.Once) &&
    !hideFrequencySwitch;

  const upgradeFrequency = useMemo(
    () =>
      frequencies.length === 2 && frequencies.includes(SourceFrequency.Once)
        ? frequencies.find((o) => o !== SourceFrequency.Once)
        : undefined,
    [frequencies]
  );

  const onToggleRecurring = useCallback(() => {
    if (!upgradeFrequency) {
      return;
    }

    setSelectedFrequency(
      selectedFrequency === SourceFrequency.Once ? upgradeFrequency : SourceFrequency.Once
    );
  }, [selectedFrequency, setSelectedFrequency, upgradeFrequency]);

  useEffect(() => {
    // If the selected frequency is not once, set the future pledge selected to false
    // Future pledge is intended as an upsell for one-time donations and should not be active for recurring donations
    if (selectedFrequency !== SourceFrequency.Once && futurePledgeSelected) {
      setFuturePledgeSelected?.(false);
    }
  }, [selectedFrequency, setFuturePledgeSelected, futurePledgeSelected]);

  const isCampaignParity = !amountPresetsOther && (amounts ?? []).length === 0;

  return (
    <Flex alignItems="center" flexDirection="column" id="form" width="full">
      <Flex flexDirection="column" width="full">
        {donationCaption || (
          <Heading as="h3" marginBottom={3}>
            {t('actionPagesBuilder:designer.finance.chooseAmount')}
          </Heading>
        )}
        {showFrequencySwitch && (
          <MultiSwitch
            options={options}
            selectedOption={selectedOption}
            setSelectedOption={(idx: number) => setSelectedFrequency(options[idx].value)}
            variant="grayscale"
          />

