import { Flex } from '@chakra-ui/react';
import { SingleCheckboxControl } from '@ui/components/formControls/CheckboxControl';
import { Label } from '@ui/components/typography';
import { formatDate } from '@ui/utils';
import { createContext, ReactNode, useContext, useEffect, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';

type Props = {
  amount: string;
  date: string;
  isChecked?: boolean;
  message?: string;
  onClick?: () => void;
};

type FuturePledgeContextType = {
  highlight: () => void;
  isHighlighted: boolean;
};
export const FuturePledgeContext = createContext<FuturePledgeContextType>({
  highlight: () => null,
  isHighlighted: false,
});

export const FuturePledgeProvider = ({ children }: { children: ReactNode }) => {
  const [highlight, setHighlight] = useState(false);
  useEffect(() => {
    if (highlight) {
      setTimeout(() => {
        setHighlight(false);
      }, 2000);
    }
  }, [highlight]);

  return (
    <FuturePledgeContext.Provider
      value={{
        highlight: () => setHighlight(true),
        isHighlighted: highlight,
      }}
    >
      {children}
    </FuturePledgeContext.Provider>
  );
};

export const FuturePledgeBanner = ({ amount, date, isChecked, message, onClick }: Props) => {
  const { t } = useTranslation('actionPagesBuilder', {
    keyPrefix: 'designer.finance.futurePledge',
  });

  const { isHighlighted } = useContext(FuturePledgeContext);
  const innerRef = useRef<HTMLDivElement>(null);
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    if (isHighlighted) {
      innerRef.current?.scrollIntoView({
        behavior: 'smooth',
        block: 'center',
      });
      innerRef.current?.focus();
    }
  }, [isHighlighted, innerRef]);

  return (
    <Flex
      background={isChecked ? (isHighlighted ? 'yellow.500' : 'yellow.200') : 'neutral.0'}
      borderColor={isChecked ? 'yellow.500' : 'yellow.400'}
      borderRadius="md"
      borderWidth={1}
      cursor="pointer"
      data-checked={isChecked ? '' : undefined}
      flexDirection="column"
      gap={4}
      id="future-pledge-banner"
      mt={4}
      onClick={(e) => {
        onClick?.();
        e.preventDefault();
      }}
      p={4}
      pt={3}
      ref={innerRef}
      transition="background-color 500ms"
      width="full"
    >
      {message && (
        <Flex flexDirection="column" gap={1}>
          {message.split('\n').map((part) => (
            <Label key={part} lineHeight="25.5px" variant="medium">
              {part}
            </Label>
          ))}
        </Flex>
      )}
      <SingleCheckboxControl
        alignItems="start"
        formControlProps={{ display: 'flex', mb: 0 }}
        isChecked={isChecked}
        name="futurePledgeBannerValue"
        onChange={onClick}
        variant="darkCheckbox"
      >
        <Label>
          {t('bannerText', {
            amount,
            date: formatDate(date, 'MM/dd'),
            interpolation: { escapeValue: false },
          })}
        </Label>
      </SingleCheckboxControl>
    </Flex>
  );
};

