} from '@chakra-ui/react';
import { CheckmarkIcon } from '@ui/assets/icons/CheckmarkIcon';
import { Button } from '@ui/components/Button';
import FilteredList from '@ui/components/FilteredList';
import { Loading } from '@ui/components/Loading';
import { ToggleChevron } from '@ui/components/ToggleChevron';
import { Label } from '@ui/components/typography';
import { Dispatch, SetStateAction, useCallback, useEffect } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import InfiniteScroll from 'react-infinite-scroll-component';

type ListOption = {
  label: string;
  value?: string;
};

type Params = Pick<BoxProps, 'pb' | 'width' | 'maxWidth'> & {
  dropdownType: 'actionPage' | 'campaign';
  fetchMoreOptions: () => void;
  floatLabel?: string;
  hasMoreOptions?: boolean;
  isInvalid?: boolean;
  isLoading: boolean;
  listOptions: ListOption[];
  onCloseFilter?: () => void;
  onOpenFilter?: () => void;
  selectFirst?: boolean;
  setSearchTerm: Dispatch<SetStateAction<string>>;
  showLabel?: boolean;
  testId?: string;
};

export const SearchableInfiniteDropdown = ({
  dropdownType,
  fetchMoreOptions,
  floatLabel,
  hasMoreOptions,
  isInvalid,
  isLoading,
  listOptions,
  maxWidth,
  onCloseFilter,
  onOpenFilter,
  pb = 4,
  selectFirst,
  setSearchTerm,
  showLabel = true,
  testId,
  width,
}: Params) => {
  const { t } = useTranslation('actionPages');
  const { setValue, trigger } = useFormContext();
  const { onClose, onOpen, ...disclosure } = useDisclosure();

  const onClosePopover = useCallback(() => {
    onClose();
    onCloseFilter?.();
  }, [onClose, onCloseFilter]);

  const onOpenPopover = useCallback(() => {
    onOpen();
    onOpenFilter?.();
  }, [onOpen, onOpenFilter]);

  const selectedItemId = useWatch({ name: `${dropdownType}Id` });
  const selectedItemName =
    useWatch({ name: `${dropdownType}Name` }) ??
    floatLabel ??
    t(`searchableDropdown.${dropdownType}.all`);

  const onFilterChange = useCallback(
    (value: string) => {
      setSearchTerm(value);
    },
    [setSearchTerm]
  );

  const onItemSelected = useCallback(
    (item: ListOption) => {
      setValue(`${dropdownType}Id`, item.value);
      setValue(`${dropdownType}Name`, item.label);
      trigger([`${dropdownType}Id`, `${dropdownType}Name`]);

      onClosePopover();
    },
    [setValue, dropdownType, trigger, onClosePopover]
  );

  useEffect(() => {
    if (selectFirst && listOptions.length > 0 && !selectedItemId) {
      onItemSelected(listOptions[0]);
    }
  }, [listOptions, onItemSelected, selectFirst, selectedItemId]);

  return (
    <VStack alignItems="stretch" maxWidth={maxWidth} pb={pb} width={width}>
      <Popover {...disclosure} isLazy matchWidth onClose={onClosePopover} onOpen={onOpenPopover}>
        <PopoverTrigger>
          <Button
            borderColor={disclosure.isOpen ? 'blue.600' : isInvalid ? 'red.500' : 'neutral.400'}
            borderWidth={isInvalid ? 2 : 1}
            data-testid={`${testId}-trigger`}
            size="lg"
            variant="secondary"
          >
            <HStack width="100%">
              <VStack alignItems="flex-start" overflow="hidden" spacing={1} width="100%">
                {showLabel && (
                  <Label color={isInvalid ? 'red.500' : undefined} fontSize="sm">
                    {t(`searchableDropdown.${dropdownType}.label`)}
                  </Label>
                )}
                <Label
                  as={Box}
                  overflow="hidden"
                  textAlign="left"
                  textOverflow="ellipsis"
                  whiteSpace="nowrap"
                  width="100%"
                >
                  {selectedItemName}
                </Label>
              </VStack>
              <Label as={Flex} flex="1" justifyContent="flex-end">
                <ToggleChevron
                  color={isInvalid ? 'red.500' : 'inherit'}
                  isOpen={disclosure.isOpen}
                />
              </Label>
            </HStack>
          </Button>
        </PopoverTrigger>
        <PopoverContent
          border="1px solid"
          borderColor="neutral.300"
          borderRadius={8}
          boxShadow="xl"
          left={0}
          p={2}
          right={0}
          width="inherit"
        >
          <FilteredList
            clearOnSelect
            inputProps={{
              autoComplete: 'off',
              mx: 1,
              size: 'sm',
              variant: 'outline',
            }}
            isLoading={isLoading}
            items={listOptions}
            onChange={onFilterChange}
            onItemSelected={onItemSelected}
            renderItems={(items, getItemProps, menuProps) => {
              return (
                <Box overflowX="hidden" overflowY="auto" {...menuProps}>
                  <InfiniteScroll
                    dataLength={listOptions.length}
                    hasMore={!!hasMoreOptions}
                    height={150}
                    loader={<Loading />}
                    next={fetchMoreOptions}
                  >
                    {items.map((item, index) => {
                      const props = getItemProps({ index, item });
                      const isActive = props['aria-selected'] === 'true';
                      return (
                        <Button
                          background={isActive ? 'neutral.100' : 'transparent'}
                          key={item.value}
                          p={1}
                          variant="menuItem"
                          {...props}
                        >
                          <Box width="24px">
                            {selectedItemId === item.value && <CheckmarkIcon />}
                          </Box>
                          <Label>{item.label}</Label>
                        </Button>
                      );
                    })}
                  </InfiniteScroll>
                </Box>
              );
            }}
          />
        </PopoverContent>
      </Popover>
    </VStack>
  );
};

