  selectFirst?: boolean;
  showLabel?: boolean;
  useActionPageId?: boolean;
  useActionPageSlug?: boolean;
};

export const ActionPageSearchableDropdown = ({
  includeAllActionPagesOption = true,
  isInvalid,
  maxWidth,
  onCloseFilter,
  onOpenFilter,
  pageType,
  pb,
  selectFirst,
  showLabel = false,
  useActionPageId = false,
  useActionPageSlug = false,
  width,
}: Props) => {
  const { t } = useTranslation('actionPages');
  const accountId = useGetAccountId();
  const [searchTerm, setSearchTerm] = useState<string>('');

  const {
    actionPages = [],
    fetchMore: fetchMoreOptions,
    hasMore: hasMoreOptions,
    isLoading,
  } = useGetAllActionPagesInfinite({
