      isInvalid={isInvalid}
      isLoading={isLoading}
      listOptions={listOptions}
      maxWidth={maxWidth}
      onCloseFilter={onCloseFilter}
      onOpenFilter={onOpenFilter}
      pb={pb}
      selectFirst={selectFirst}
      setSearchTerm={setSearchTerm}
      showLabel={showLabel}
      testId="action-page-selector"
      width={width}
    />
  );
};

