import { IErrorResponse } from '@domain/error';
import { Scope } from '@domain/scope';
import { ApiClient } from '@service/anedot/client';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useGetAccountId } from '@utils/useGetAccountId';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type HookParams = {
  showToast: boolean;
};

type QueryParams = {
  description: string;
  name: string;
};

const defaultHookParams: HookParams = {
  showToast: true,
};

export const useCreateScope = ({ showToast }: HookParams = defaultHookParams) => {
  const { t } = useTranslation('settings', { keyPrefix: 'teams.toasts.useCreateScope' });
  const { refreshCache: refreshScopeCache } = useCacheHelper(resourceKeys.scopes);
  const accountId = useGetAccountId();
  const { showToast: doShowToast } = useToast();

  const mutation = useMutation<Scope, IErrorResponse, QueryParams>(
    (params: QueryParams) => new ApiClient().post('/scopes', { accountId, ...params }),
    {
      onError: () => {
        if (showToast) {
          doShowToast({
            message: t('failure'),
            variant: 'error',
          });
        }
      },
      onSuccess: (scope) => {
        if (showToast) {
          doShowToast({
            message: t('success'),
            variant: 'success',
          });
        }

        return refreshScopeCache(scope.id);
      },
    }
  );

  return {
    createScope: mutation.mutate,
    error: mutation.error,
    isLoading: mutation.isLoading,
  };
};

