import { Flex, VStack } from '@chakra-ui/react';
import { Button } from '@ui/components/Button';
import { FormDateTimeControl } from '@ui/components/formControls/DateTimeControl';
import { countEveryMatchingKeyWithDefault, makeFilter } from '@ui/utils/makeFilter';
import { endOfDay, endOfMonth, startOfDay, startOfMonth, startOfYear, subMonths } from 'date-fns';
import { useFormContext, useWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import * as yup from 'yup';
import { deserializeDate, serializeDate } from '../serde';
import { isDateRangeAllTime, isDateRangePreviousMonth, isDateRangeYearToDate } from './utils';

export type DateRangeParams = Partial<{
  endDate: string;
  startDate: string;
}>;

export type DateFilterForm = Partial<{
  endDate: Nullable<Date>;
  startDate: Nullable<Date>;
}>;

const dateFilterParams: (keyof DateRangeParams)[] = ['endDate', 'startDate'];

export const useDateFilterSchema = () => {
  const { t } = useTranslation('finance', { keyPrefix: 'entries.filterDrawer.date' });
  return yup.object().shape({
    endDate: yup
      .date()
      .nullable()
      .typeError(t('endDate.validation.type'))
      .when('startDate', {
        is: (startDate: Date | undefined) => !!startDate,
        then: (s) => s.min(yup.ref('startDate'), t('endDate.validation.beforeStart')),
      }),
    startDate: yup.date().nullable().typeError(t('startDate.validation.type')),
  });
};

export const dateFilter = makeFilter<DateFilterForm, DateRangeParams>(
  dateFilterParams,
  {
    endDate: null,
    startDate: null,
  },
  ({ endDate, startDate }) => ({
    endDate: serializeDate(endDate),
    startDate: serializeDate(startDate),
  }),
  ({ endDate, startDate }) => ({
    endDate: deserializeDate(endDate),
    startDate: deserializeDate(startDate),
  })
);

export const anyableDateFilter = (initialValues: Partial<DateFilterForm> = {}) =>
  makeFilter<DateFilterForm, DateRangeParams>(
    dateFilterParams,
    {
      endDate: null,
      startDate: null,
      ...initialValues,
    },
    ({ endDate, startDate }) => ({
      endDate: serializeDate(endDate, 'any'),
      startDate: serializeDate(startDate, 'any'),
    }),
    ({ endDate, startDate }) => ({
      endDate: deserializeDate(endDate, 'any'),
      startDate: deserializeDate(startDate, 'any'),
    }),
    (filters) => countEveryMatchingKeyWithDefault(filters, dateFilterParams, 'any')
  );

export const anyableYearToDateFilter = anyableDateFilter({
  endDate: new Date(),
  startDate: startOfYear(new Date()),
});

export const DateFilter = () => {
  const { t } = useTranslation('finance', { keyPrefix: 'entries.filterDrawer.date' });

  return (
    <Flex>
      <FormDateTimeControl
        // `mr` necessary to avoid react-date-picker hidden element from affecting spacing
        formControlProps={{ mr: 1 }}
        label={t('startDate.label')}
        maxDate={new Date()}
        name="startDate"
        variant="permafloating"
      />
      <FormDateTimeControl
        // `ml` necessary to avoid react-date-picker hidden element from affecting spacing
        formControlProps={{ ml: 1 }}
        label={t('endDate.label')}
        maxDate={new Date()}
        name="endDate"
        variant="permafloating"
      />
    </Flex>
  );
};

export const DateFilterWithPresets = () => {
  const { t } = useTranslation('finance', { keyPrefix: 'entries.filterDrawer.date' });
  const { setValue } = useFormContext<DateFilterForm>();
  const { endDate, startDate } = useWatch<DateFilterForm>();

  const setDateRange = (start: Nullable<Date>, end: Nullable<Date>) => {
    setValue('startDate', start ? startOfDay(start) : null, { shouldDirty: true });
    setValue('endDate', end ? endOfDay(end) : null, { shouldDirty: true });
  };

  const handleYearToDate = () => {
    const now = new Date();
    setDateRange(startOfYear(now), now);
  };

  const handlePreviousMonth = () => {
    const now = new Date();
    const startOfLastMonth = startOfMonth(subMonths(now, 1));
    const endOfLastMonth = endOfMonth(subMonths(now, 1));
    setDateRange(startOfLastMonth, endOfLastMonth);
  };

  const handleAllTime = () => {
    setDateRange(null, null);
  };

  return (
    <VStack alignItems="stretch">
      <Flex gap={1}>
        <Button
          flex="1"
          onClick={handleYearToDate}
          size="lg"
          variant={
            isDateRangeYearToDate(startDate ?? null, endDate ?? null) ? 'primary' : 'secondary'
          }
        >
          Year to Date
        </Button>
        <Button
          flex="1"
          onClick={handlePreviousMonth}
          size="lg"
          variant={
            isDateRangePreviousMonth(startDate ?? null, endDate ?? null) ? 'primary' : 'secondary'
          }
        >
          Last Month
        </Button>
        <Button
          flex="1"
          onClick={handleAllTime}
          size="lg"
          variant={isDateRangeAllTime(startDate ?? null, endDate ?? null) ? 'primary' : 'secondary'}
        >
          All Time
        </Button>
      </Flex>
      <Flex>
        <FormDateTimeControl
          // `mr` necessary to avoid react-date-picker hidden element from affecting spacing
          formControlProps={{ mr: 1 }}
          label={t('startDate.label')}
          maxDate={new Date()}
          name="startDate"
          variant="permafloating"
        />
        <FormDateTimeControl
          // `ml` necessary to avoid react-date-picker hidden element from affecting spacing
          formControlProps={{ ml: 1 }}
          label={t('endDate.label')}
          maxDate={new Date()}
          name="endDate"
          variant="permafloating"
        />
      </Flex>
    </VStack>
  );
};

