import { BankAccount, BankAccountReplacement } from '@domain/bankAccount';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type MutationParams = Omit<BankAccountReplacement, 'accountId'> & {
  oldBankAccountId: string;
};

export const useReplaceBankAccount = () => {
  const { showToast } = useToast();
  const { refreshCache } = useCacheHelper(resourceKeys.bankAccounts);
  const { refreshCache: refreshFunds } = useCacheHelper(resourceKeys.actionPagesFunds);
  const { currentAccount } = useGetAccount();
  const { t } = useTranslation('settings', { keyPrefix: 'bankAccounts' });

  const { error, isLoading, mutate, mutateAsync } = useMutation<
    BankAccount,
    IErrorResponse,
    MutationParams
  >(
    ({ newBankAccountId, oldBankAccountId }) => {
      if (!currentAccount?.id) {
        throw new Error('Account Id is required to Replace a bank account');
      }

      return new ApiClient().post(`/bank_accounts/${oldBankAccountId}/replace`, {
        accountId: currentAccount.id,
        newBankAccountId,
      });
    },
    {
      onError: () => {
        showToast({
          message: t('state.replaceFailure'),
          variant: 'error',
        });
      },
      onSuccess: async (_, { newBankAccountId, oldBankAccountId }) => {
        showToast({
          message: t('state.replaceSuccess'),
          variant: 'success',
        });

        await Promise.all([
          refreshCache(newBankAccountId),
          refreshCache(oldBankAccountId),
          refreshFunds(''),
        ]);
      },
    }
  );

  return {
    bankAccountReplaceError: error,
    isReplacingBankAccount: isLoading,
    replaceBankAccount: mutate,
    replaceBankAccountAsync: mutateAsync,
  };
};

