import { AccountImage, Image } from '@domain/account';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { AxiosRequestConfig } from 'axios';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type Params = {
  shouldShowToast?: boolean;
};

export const uploadImage = async (
  { file, originalFilename, translationsAttributes }: AccountImage,
  accountId?: string,
  onUploadProgress?: AxiosRequestConfig['onUploadProgress']
) => {
  const body = { accountId, file, originalFilename, translationsAttributes };

  return new ApiClient().post<AccountImage, Image>(`/account_images`, body, {
    onUploadProgress,
  });
};

export const useUploadImage = ({ shouldShowToast = true }: Params = {}) => {
  const { showToast } = useToast();
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;
  const { refreshCache } = useCacheHelper(resourceKeys.accountImages);
  const [progress, setProgress] = useState<number>();
  const { t } = useTranslation('mediaManager');

  const mutation = useMutation<Image, IErrorResponse, AccountImage, string>(
    ({ file, id, originalFilename, translationsAttributes }: AccountImage) => {
      if (id) {
        const body = { accountId, id, originalFilename, translationsAttributes };
        return new ApiClient().put<AccountImage, Image>(`/account_images/${id}`, body, {
          onUploadProgress: (progressEvent) =>
            setProgress((progressEvent.loaded * 100) / progressEvent.total),
        });
      }

      const body = { accountId, file, originalFilename, translationsAttributes };
      return new ApiClient().post<AccountImage, Image>(`/account_images`, body, {
        onUploadProgress: (progressEvent) =>
          setProgress((progressEvent.loaded * 100) / progressEvent.total),
      });
    },
    {
      onError: () => {
        showToast({
          message: t('service.upload.failed'),
          variant: 'error',
        });
      },
      onSuccess: (data) => {
        if (shouldShowToast) {
          showToast({
            message: t('service.upload.success'),
            variant: 'success',
          });
        }
        return refreshCache(data.id!);
      },
    }
  );

  return {
    data: mutation.data,
    error: mutation.error,
    isLoading: mutation.isLoading,
    progress,
    uploadImage: mutation.mutateAsync,
  };
};

