import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { makeSearchParams } from '@utils';
import { useTranslation } from 'react-i18next';
import { UseMutationResult, useMutation } from 'react-query';

export const useDeleteImage = (): UseMutationResult<string, IErrorResponse, string, string> => {
  const { t } = useTranslation('mediaManager');
  const { showToast } = useToast();
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;
  const { refreshCache } = useCacheHelper(resourceKeys.accountImages);

  const mutation = useMutation<string, IErrorResponse, string, string>(
    (id: string) => {
      const searchParams = makeSearchParams({
        account_id: accountId,
      });

      return new ApiClient().delete(`/account_images/${id}?${searchParams.toString()}`);
    },
    {
      onError: (response) => {
        if (
          response?.errors?.[0].details[0] === 'is still being used' ||
          response?.errors?.[0].details[0]?.includes('must be taken out of use')
        ) {
          showToast({
            message: t('service.delete.imageBeingUsed'),
            variant: 'error',
          });
        } else {
          showToast({
            message: t('service.delete.failed'),
            variant: 'error',
          });
        }
      },
      onSuccess: (_data, id) => {
        showToast({
          message: t('service.delete.success'),
          variant: 'success',
        });

        return refreshCache(id);
      },
    }
  );

  return mutation;
};

