import { IErrorResponse } from '@domain/error';
import { Tag } from '@domain/tag';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type Params = {
  tag: Tag;
};

type Response = {
  error: IErrorResponse | null;
  isLoading: boolean;
  updateTag: (params: Params) => Promise<Tag>;
};

export const useUpdateTag = (
  {
    showErrorToast = true,
    showSuccessToast = true,
  }: {
    showErrorToast?: boolean;
    showSuccessToast?: boolean;
  } = { showErrorToast: true, showSuccessToast: true }
): Response => {
  const { t } = useTranslation('common');
  const { showToast } = useToast();
  const { refreshCache: refreshTagCache } = useCacheHelper(resourceKeys.tags);
  const { refreshCache: refreshActionPageCache } = useCacheHelper(resourceKeys.actionPages);
  const { refreshCache: refreshScopesCache } = useCacheHelper(resourceKeys.scopes);
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;

  const mutation = useMutation<Tag, IErrorResponse, Params, string>(
    ({ tag: { id: tagId, ...tagAttributes } }: Params) => {
      return new ApiClient().put(`/access_tags/${tagId}`, { accountId, ...tagAttributes });
    },
    {
      onError: () => {
        if (showErrorToast) {
          showToast({
            message: t('tags.state.update.error'),
            variant: 'error',
          });
        }
      },
      onSuccess: (_data, { tag }) => {
        if (showSuccessToast) {
          showToast({
            message: t('tags.state.update.success'),
            variant: 'success',
          });
        }

        // When tags are used in other views this will need to chain the refresh
        // of those caches as well
        return refreshTagCache(tag.id!).then(() => {
          refreshActionPageCache('');
          refreshScopesCache('');
        });
      },
    }
  );

  return {
    error: mutation.error,
    isLoading: mutation.isLoading,
    updateTag: mutation.mutateAsync,
  };
};

