          variant: 'success',
        });

        return refreshTagCache(accessTagId).then(() => {
          refreshActionPageCache('');
          refreshScopesCache('');
        });
      },
    }
  );

  return {
    deleteTag: mutation.mutate,
    error: mutation.error,
