import {
  DonorStatementConfiguration,
  DonorStatementConfigurationUpdate,
} from 'src/domain/donorStatements';

type HookOptions = {
  showToast?: boolean;
};

const defaultHookOptions: HookOptions = {
  showToast: true,
};

export const useUpdateDonorStatementConfiguration = ({
  showToast,
}: HookOptions = defaultHookOptions) => {
  const { showToast: doShowToast } = useToast();
  const accountId = useGetAccountId();
  const { refreshCache } = useCacheHelper(resourceKeys.donorStatementConfiguration);

  const { t } = useTranslation('settings', { keyPrefix: 'donorStatements.toasts' });

  const mutation = useMutation<
