      return new ApiClient().put<DonorStatementConfigurationUpdate, DonorStatementConfiguration>(
        `/donor_statement_configuration`,
        body
      );
    },
    {
      onError: () => {
        if (showToast) {
          doShowToast({ message: t('save.failure'), variant: 'error' });
