  BillingAgreementType,
} from '@domain/billingAgreement';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

export const useCreateBillingAgreement = () => {
  const { t } = useTranslation('billingAgreements', { keyPrefix: 'state' });
  const { refreshCache } = useCacheHelper(resourceKeys.billingAgreements);
  const { currentAccount } = useGetAccount();
  const { showToast } = useToast();

  const { error, isLoading, mutate } = useMutation<
    BillingAgreement,
    IErrorResponse,
    Omit<BillingAgreementCreate, 'accountId'>
  >(
    (body) => {
      if (!currentAccount?.id) {
        throw new Error('Account Id is required to create a bank account');
      }

      const isOffline = body.type === BillingAgreementType.Offline;
      const payload = {
        ...body,
        accountId: currentAccount.id,
        // For offline agreements, set all rates to 0 and disable certain features
        ...(isOffline && {
          excludeExternalFunds: false,
          includeRecurrences: false,
          markupRate: 0,
          returnMarkupFees: false,
        }),
      };

      return new ApiClient().post<BillingAgreementCreate, BillingAgreement>(
        '/billing_agreements',
        payload
      );
    },
    {
      onError: () => {
        showToast({ message: t('createFailure'), variant: 'error' });
      },
      onSuccess: (data) => {
        showToast({ message: t('createSuccess'), variant: 'success' });
        return refreshCache(data.id);
      },
    }
  );

  return {
    billingAgreementCreationError: error,
    createBillingAgreement: mutate,
    isCreatingBillingAgreement: isLoading,
  };
};

