import { BillingAgreement, BillingAgreementUpdate } from '@domain/billingAgreement';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { createContext, useContext } from 'react';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type MutationParams = Omit<BillingAgreementUpdate, 'accountId'> & {
  id: string;
};

const _useUpdateBillingAgreement = () => {
  const { currentAccount: { id: accountId } = {} } = useGetAccount();
  const { refreshCache: refreshBillingAgreementsCache } = useCacheHelper(
    resourceKeys.billingAgreements
  );
  const { refreshCache: refreshActionPagesCache } = useCacheHelper(resourceKeys.actionPages);
  const { t } = useTranslation('billingAgreements', { keyPrefix: 'state' });
  const { showToast } = useToast();

  const { error, isLoading, mutate, mutateAsync } = useMutation<
    BillingAgreement,
    IErrorResponse,
    MutationParams
  >(
    ({ id, ...update }) => {
      if (!accountId) {
        throw new Error('Account Id is required to update a billing agreement');
      }

      return new ApiClient().put<BillingAgreementUpdate, BillingAgreement>(
        `/billing_agreements/${id}`,
        {
          ...update,
          accountId,
        }
      );
    },
    {
      onError: ({ errors }) => {
        const message = errors?.[0]?.details ? `: ${errors[0].details}` : '';
        showToast({ message: `${t('updateFailure')}${message}`, variant: 'error' });
      },
      onSuccess: async ({ actionPageIds, id }: BillingAgreement) => {
        showToast({ message: t('updateSuccess'), variant: 'success' });
        await Promise.all([
          refreshBillingAgreementsCache(id),
          ...actionPageIds.map((pageId) => refreshActionPagesCache(pageId)),
        ]);
      },
    }
  );

  return {
    billingAgreementUpdateError: error,
    isUpdatingBillingAgreement: isLoading,
    updateBillingAgreement: mutate,
    updateBillingAgreementAsync: mutateAsync,
  };
};

export const UseUpdateBillingAgreementContext = createContext(_useUpdateBillingAgreement);
export const useUpdateBillingAgreement = () => useContext(UseUpdateBillingAgreementContext)();

