import { IOption } from '@constants';
import { AccessLevel } from '@domain/user';
import { usePermissions } from '@state/utils';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { PresetPermissionListName } from './presetPermissionListName';
import { useGetAllPermissionLists } from './useGetAllPermissionLists';

type Aggregate = {
  adminListId?: string;
  permissionListOptions?: IOption[];
  standardListId?: string;
  superAdminListId?: string;
};

export const usePermissionListOptions = () => {
  const { t } = useTranslation();
  const { isFetchedPermissionLists, permissionLists } = useGetAllPermissionLists();
  const { admin, canAssignPermissionList, owner, staffRole, superadmin } = usePermissions();
  const canAssignSuperAdmins = staffRole || superadmin || owner;
  const canAssignAdmins = canAssignSuperAdmins || admin;

  const campaignAccessLevelOptions: IOption[] = [
    { label: t('campaignAccessLevels.superadmin'), value: AccessLevel.SuperAdmin },
    { label: t('campaignAccessLevels.admin'), value: AccessLevel.Admin },
    { label: t('campaignAccessLevels.standard'), value: AccessLevel.Standard },
    { label: t('campaignAccessLevels.standardLimited'), value: AccessLevel.StandardLimited },
  ];

  const { adminListId, permissionListOptions, standardListId, superAdminListId } = useMemo(
    () =>
      permissionLists?.reduce<Aggregate>(
        (acc, permissionList) => {
          const { id, name } = permissionList;

          const option: IOption = {
            disabled: !canAssignPermissionList(permissionList),
            label: name,
            value: id,
          };

          switch (name as PresetPermissionListName) {
            case PresetPermissionListName.SuperAdmin:
              acc.superAdminListId = option.value;
              option.disabled = !canAssignSuperAdmins;
              break;
            case PresetPermissionListName.Admin:
              acc.adminListId = option.value;
              option.disabled = !canAssignAdmins;
              break;
            case PresetPermissionListName.Standard:
              acc.standardListId = option.value;
              break;
            case PresetPermissionListName.Owner:
              return acc;
            default:
              break;
          }

          acc.permissionListOptions?.push(option);
          return acc;
        },
        {
          adminListId: undefined,
          permissionListOptions: [],
          standardListId: undefined,
          superAdminListId: undefined,
        }
      ) ?? {},
    [permissionLists, canAssignPermissionList, canAssignSuperAdmins, canAssignAdmins]
  );

  const getAccessLevelByPermissionListId = (permissionListId = '') =>
    permissionListId === superAdminListId
      ? AccessLevel.SuperAdmin
      : permissionListId === adminListId
        ? AccessLevel.Admin
        : AccessLevel.Standard;

  return {
    adminListId,
    campaignAccessLevelOptions,
    getAccessLevelByPermissionListId,
    isFetchedPermissionLists,
    permissionListOptions,
    standardListId,
    superAdminListId,
  };
};

